// Extract a snippet of text for the AI to analyze
const post = items[0].json;
let snippet = post.title.rendered + "\n\n";

// Try to grab raw content or intro if available
if (post.content && post.content.rendered) {
    snippet += post.content.rendered.replace(/<[^>]*>?/gm, ''); // Strip HTML
} else if (post.acf && post.acf.intro) {
    snippet += post.acf.intro;
}

// Limit to 1000 chars to save OpenAI tokens
return [{
  json: {
    ...post,
    textSnippet: snippet.substring(0, 1000)
  }
}];

const originalPost = $items("Prepare Text Snippet")[0].json;
const detectedLang = items[0].json.message.content.trim().toLowerCase();
const currentWpLang = originalPost.lang || 'en'; // Defaults to 'en' if not set

// 👉 UPDATE THIS ARRAY to include all the languages your site supports
const allSupported = ['en', 'fr', 'de'];
let targetLangs = allSupported.filter(l => l !== detectedLang);

// 2. Check which translations already exist so we don't duplicate
const existingTranslations = originalPost.translations || {};
const needed = [];

targetLangs.forEach(lang => {
  if (!existingTranslations[lang]) {
    needed.push(lang);
  }
});

// 3. Do we need to fix the original post's flag in WP?
const needsLangFix = (detectedLang !== currentWpLang) && allSupported.includes(detectedLang);

return [{
  json: {
    originalPost: originalPost,
    detectedLang: detectedLang,
    languagesNeeded: needed,
    needsLangFix: needsLangFix,
    originalId: originalPost.id,
    postTypeUrl: originalPost._links.self[0].href // e.g., https://.../wp/v2/posts/123
  }
}];

