const input = items[0].json;
const post = input.originalPost;
const acf = post.acf || {};

// === 🚨 IMPORTANT: UPDATE THESE KEYS 🚨 ===
// These keys are specific to the Advanced Custom Fields (ACF) setup. 
// Replace these with the actual field names you use in your own ACF configuration!
const textKeys = ['title', 'headline', 'subheadline', 'text', 'description', 'body', 'intro', 'buttonLabel', 'quote', 'ctaText', 'chipText', 'content', 'keyCapabilities', 'sectionDescription', 'iconName', 'featureTitle', 'featureDescription', 'planName', 'planDescription', 'features', 'question', 'answer', 'label', 'context', 'authorRole', 'step_title', 'step_description'];

let stringsToTranslate = [post.title.rendered];
let mapPaths = ['post_title'];

if (post.content && post.content.rendered && post.content.rendered.trim() !== '') {
    stringsToTranslate.push(post.content.rendered);
    mapPaths.push('post_content');
}

if (acf.intro) {
  stringsToTranslate.push(acf.intro);
  mapPaths.push('acf.intro');
}

function walk(obj, path) {
  if (Array.isArray(obj)) {
    obj.forEach((item, index) => walk(item, `${path}[${index}]`));
  } else if (typeof obj === 'object' && obj !== null) {
    for (const key in obj) {
      if (textKeys.includes(key) && typeof obj[key] === 'string' && obj[key].trim() !== '') {
        stringsToTranslate.push(obj[key]);
        mapPaths.push(`${path}.${key}`);
      } else {
        walk(obj[key], `${path}.${key}`);
      }
    }
  }
}

// === 🚨 CUSTOM ACF FLEXIBLE CONTENT 🚨 ===
// 'product_flexible' is a specific field identifier. 
// If you use flexible content or repeater fields, adjust or duplicate the line below.
if (acf.product_flexible) walk(acf.product_flexible, 'acf.product_flexible');

return [{ json: { ...input, stringsToTranslate, mapPaths } }];

const splitItems = $items("Split by Target Lang");
const results = [];

function set(obj, path, value) {
    var schema = obj, pList = path.split('.'), len = pList.length;
    for(var i = 0; i < len-1; i++) {
        var elem = pList[i];
        if(elem.includes('[')) {
             const arrayName = elem.split('[')[0];
             const index = parseInt(elem.split('[')[1].replace(']', ''));
             schema = schema[arrayName][index];
        } else {
             if( !schema[elem] ) schema[elem] = {}
             schema = schema[elem];
        }
    }
    var lastElem = pList[len-1];
     if(lastElem.includes('[')) {
         const arrayName = lastElem.split('[')[0];
         const index = parseInt(lastElem.split('[')[1].replace(']', ''));
         schema[arrayName][index] = value;
    } else {
         schema[lastElem] = value;
    }
}

// Cleans inside Arrays and Objects
function cleanAcf(obj) {
    if (!obj) return;
    if (Array.isArray(obj)) {
        obj.forEach(item => cleanAcf(item));
    } else if (typeof obj === 'object') {
        Object.keys(obj).forEach(key => {
            if (obj[key] === "") {
                obj[key] = null; 
            } else if (typeof obj[key] === 'object' && obj[key] !== null) {
                cleanAcf(obj[key]);
            }
        });
    }
}

for (let i = 0; i < items.length; i++) {
    const translatedTexts = items[i].json.translations;
    const originalData = splitItems[i].json;
    const mapPaths = originalData.mapPaths;

    let newPost = JSON.parse(JSON.stringify(originalData.originalPost));

    mapPaths.forEach((path, index) => {
        const translatedString = translatedTexts[index].text;

        if (path === 'post_title') {
            newPost.title.raw = translatedString;
            newPost.title.rendered = translatedString;
        } else if (path === 'post_content') {
            newPost.content.raw = translatedString;
            newPost.content.rendered = translatedString;
        } else if (path.startsWith('acf.')) {
            set(newPost.acf, path.replace('acf.', ''), translatedString);
        }
    });

    cleanAcf(newPost.acf);

    const originalUrl = originalData.postTypeUrl;
    const baseUrl = originalUrl.substring(0, originalUrl.lastIndexOf('/'));

    results.push({
        json: {
            lang: originalData.languagesNeeded, 
            originalId: originalData.originalId,
            newTitle: newPost.title.raw,
            newAcf: newPost.acf,
            newContent: newPost.content?.raw || "",
            createUrl: baseUrl
        }
    });
}

return results;
